import java.util.Scanner;

public class SecureBufferUsage {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limit the length of the input to prevent buffer overflow
        int maxLength = Math.min(name.length(), 10);

        char[] buffer = new char[10];
        name.getChars(0, maxLength, buffer, 0);

        // Ensure bounds checking on the array access
        for (int i = 0; i < maxLength; i++) {
            System.out.print(buffer[i]);
        }

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
